# Configuration Hot-Reloading

import threading
import time
import os

class ConfigReloader:
    def __init__(self, config_path, reload_interval=5):
        self.config_path = config_path
        self.reload_interval = reload_interval
        self.last_modified = None
        self.running = False
        self.config = {}

    def load_config(self):
        try:
            with open(self.config_path, 'r') as f:
                # For example, assume config is key=value pairs
                self.config = {}
                for line in f:
                    if '=' in line:
                        key, value = line.strip().split('=', 1)
                        self.config[key] = value
                print(f"[ConfigReloader] Config loaded: {self.config}")
        except Exception as e:
            print(f"[ConfigReloader] Failed to load config: {e}")

    def watch_config(self):
        self.running = True
        while self.running:
            try:
                modified = os.path.getmtime(self.config_path)
                if self.last_modified is None or modified > self.last_modified:
                    self.last_modified = modified
                    self.load_config()
            except FileNotFoundError:
                print(f"[ConfigReloader] Config file not found: {self.config_path}")
            time.sleep(self.reload_interval)

    def start(self):
        threading.Thread(target=self.watch_config, daemon=True).start()
        print("[ConfigReloader] Started config watcher.")

    def stop(self):
        self.running = False

