# Priority Task Scheduler with Timeouts

import threading
import time
import heapq

class PriorityTaskScheduler:
    def __init__(self):
        self.tasks = []
        self.lock = threading.Lock()
        self.running = False

    def add_task(self, func, priority=10, timeout=None):
        with self.lock:
            heapq.heappush(self.tasks, (priority, time.time(), func, timeout))
            print(f"[PriorityTaskScheduler] Task added with priority {priority}")

    def _run_task(self, func, timeout):
        if timeout:
            timer = threading.Timer(timeout, lambda: print("[PriorityTaskScheduler] Task timeout reached."))
            timer.start()
            func()
            timer.cancel()
        else:
            func()

    def start(self):
        if not self.running:
            self.running = True
            threading.Thread(target=self._run, daemon=True).start()
            print("[PriorityTaskScheduler] Scheduler started.")

    def _run(self):
        while self.running:
            with self.lock:
                if self.tasks:
                    priority, _, func, timeout = heapq.heappop(self.tasks)
                    print(f"[PriorityTaskScheduler] Running task with priority {priority}")
                else:
                    func = None
            if func:
                self._run_task(func, timeout)
            else:
                time.sleep(1)

    def stop(self):
        self.running = False
        print("[PriorityTaskScheduler] Scheduler stopped.")

