import queue
import threading

class CommunicationDispatcher:
    def __init__(self):
        self.channels = {}
        self.message_queues = {}

    def register_channel(self, channel_name, handler):
        self.channels[channel_name] = handler
        self.message_queues[channel_name] = queue.Queue()
        threading.Thread(target=self._process_queue, args=(channel_name,), daemon=True).start()
        print(f"[CommunicationDispatcher] Channel '{channel_name}' registered.")

    def send_message(self, channel_name, message):
        if channel_name in self.message_queues:
            self.message_queues[channel_name].put(message)
            print(f"[CommunicationDispatcher] Message queued on channel '{channel_name}'.")
        else:
            print(f"[CommunicationDispatcher] Channel '{channel_name}' not found.")

    def _process_queue(self, channel_name):
        queue_ = self.message_queues[channel_name]
        handler = self.channels[channel_name]
        while True:
            message = queue_.get()
            try:
                handler(message)
            except Exception as e:
                print(f"[CommunicationDispatcher] Error processing message on channel '{channel_name}': {e}")
            queue_.task_done()

